def main():
    """Main entry point for the transaction consumer."""
    import os

    bootstrap_servers = os.environ.get('KAFKA_BOOTSTRAP_SERVERS', 'localhost:9092')
    topics = os.environ.get('KAFKA_TOPICS', 'financial-transactions').split(',')
    group_id = os.environ.get('KAFKA_GROUP_ID', 'transaction-processor-group')

    consumer = FinancialTransactionConsumer(
        bootstrap_servers=bootstrap_servers,
        topics=topics,
        group_id=group_id,
    )

    # Seed demo balances
    seed_demo_balances(consumer.processor)

    # Example: Register a custom handler for a specific transaction type
    def handle_crypto_transaction(transaction: Transaction) -> Dict[str, Any]:
        logger.info(
            f"CRYPTO: Processing crypto transaction {transaction.transaction_id} "
            f"Amount: {transaction.amount} {transaction.currency}"
        )
        return {
            'status': 'completed',
            'type': 'crypto',
            'transaction_id': transaction.transaction_id
        }

    consumer.register_custom_handler('crypto', handle_crypto_transaction)

    logger.info("Starting Financial Transaction Consumer...")
    consumer.start()


if __name__ == '__main__':
    main()